def findMedianSortedArrays(nums1,nums2):
    merged=sorted(nums1+nums2)
    n=len(merged)
    if n%2==0:
        return (merged[n//2-1]+merged[n//2])/2
    else:
        return merged[n//2]

def isMatch(s,p):
    if not p:
        return not s
    first_match=bool(s) and p[0] in {s[0],'.'}
    if len(p)>=2 and p[1]=='*':
        return isMatch(s,p[2:]) or (first_match and isMatch(s[1:],p))
    else:
        return first_match and isMatch(s[1:],p[1:])

import heapq

class ListNode:
    def __init__(self,val=0,next=None):
        self.val=val
        self.next=next

def mergeKLists(lists):
    heap=[]
    for l in lists:
        while l:
            heapq.heappush(heap,l.val)
            l=l.next
    dummy=ListNode()
    current=dummy
    while heap:
        current.next=ListNode(heapq.heappop(heap))
        current=current.next
    return dummy.next

def trap(height):
    if not height:
        return 0
    left,right=0,len(height)-1
    left_max,right_max=height[left],height[right]
    water=0
    while left<right:
        if left_max<right_max:
            left+=1
            left_max=max(left_max,height[left])
            water+=left_max-height[left]
        else:
            right-=1
            right_max=max(right_max,height[right])
            water+=right_max-height[right]
    return water

def isMatch(s,p):
    dp=[[False]*(len(p)+1) for _ in range(len(s)+1)]
    dp[0][0]=True
    for j in range(1,len(p)+1):
        if p[j-1]=='*':
            dp[0][j]=dp[0][j-1]
    for i in range(1,len(s)+1):
        for j in range(1,len(p)+1):
            if p[j-1]=='*':
                dp[i][j]=dp[i-1][j] or dp[i][j-1]
            elif p[j-1]=='?' or s[i-1]==p[j-1]:
                dp[i][j]=dp[i-1][j-1]
    return dp[-1][-1]

def longestValidParentheses(s):
    stack=[-1]
    max_length=0
    for i in range(len(s)):
        if s[i]=='(':
            stack.append(i)
        else:
            stack.pop()
            if not stack:
                stack.append(i)
            else:
                max_length=max(max_length,i-stack[-1])
    return max_length

def minDistance(word1,word2):
    m,n=len(word1),len(word2)
    dp=[[0]*(n+1) for _ in range(m+1)]
    for i in range(m+1):
        dp[i][0]=i
    for j in range(n+1):
        dp[0][j]=j
    for i in range(1,m+1):
        for j in range(1,n+1):
            if word1[i-1]==word2[j-1]:
                dp[i][j]=dp[i-1][j-1]
            else:
                dp[i][j]=1+min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1])
    return dp[m][n]

def maximalRectangle(matrix):
    if not matrix:
        return 0
    max_area=0
    dp=[0]*len(matrix[0])
    for row in matrix:
        for j in range(len(row)):
            dp[j]=dp[j]+1 if row[j]=='1' else 0
        stack=[]
        for i,h in enumerate(dp+[0]):
            while stack and h<dp[stack[-1]]:
                height=dp[stack.pop()]
                width=i if not stack else i-stack[-1]-1
                max_area=max(max_area,height*width)
            stack.append(i)
    return max_area

def findLadders(beginWord,endWord,wordList):
    from collections import defaultdict,deque
    wordList=set(wordList)
    if endWord not in wordList:
        return []
    graph=defaultdict(list)
    queue=deque([beginWord])
    found=False
    while queue and not found:
        level_size=len(queue)
        visited=set()
        for _ in range(level_size):
            word=queue.popleft()
            for i in range(len(word)):
                for c in 'abcdefghijklmnopqrstuvwxyz':
                    new_word=word[:i]+c+word[i+1:]
                    if new_word==endWord:
                        found=True
                    if new_word in wordList:
                        visited.add(new_word)
                        graph[word].append(new_word)
        for word in visited:
            wordList.remove(word)
            queue.append(word)
    result=[]
    def backtrack(word,path):
        if word==endWord:
            result.append(path)
            return
        for neighbor in graph[word]:
            backtrack(neighbor,path+[neighbor])
    backtrack(beginWord,[beginWord])
    return result

class TreeNode:
    def __init__(self,val=0,left=None,right=None):
        self.val=val
        self.left=left
        self.right=right

class Codec:
    def serialize(self,root):
        def helper(node):
            if not node:
                return 'None,'
            return str(node.val)+','+helper(node.left)+helper(node.right)
        return helper(root)
    def deserialize(self,data):
        def helper(nodes):
            val=next(nodes)
            if val=='None':
                return None
            node=TreeNode(int(val))
            node.left=helper(nodes)
            node.right=helper(nodes)
            return node
        nodes=iter(data.split(','))
        return helper(nodes)

def maxSlidingWindow(nums,k):
    from collections import deque
    q=deque()
    result=[]
    for i,num in enumerate(nums):
        while q and nums[q[-1]]<num:
            q.pop()
        q.append(i)
        if q[0]==i-k:
            q.popleft()
        if i>=k-1:
            result.append(nums[q[0]])
    return result

def maxCoins(nums):
    nums=[1]+nums+[1]
    n=len(nums)
    dp=[[0]*n for _ in range(n)]
    for length in range(2,n):
        for left in range(n-length):
            right=left+length
            for i in range(left+1,right):
                dp[left][right]=max(dp[left][right],nums[left]*nums[i]*nums[right]+dp[left][i]+dp[i][right])
    return dp[0][n-1]

def removeInvalidParentheses(s):
    def is_valid(s):
        count=0
        for char in s:
            if char=='(':
                count+=1
            elif char==')':
                count-=1
                if count<0:
                    return False
        return count==0
    level={s}
    while True:
        valid=list(filter(is_valid,level))
        if valid:
            return valid
        next_level=set()
        for s in level:
            for i in range(len(s)):
                if s[i] in '()':
                    next_level.add(s[:i]+s[i+1:])
        level=next_level

def longestIncreasingPath(matrix):
    if not matrix:
        return 0
    m,n=len(matrix),len(matrix[0])
    directions=[(0,1),(1,0),(0,-1),(-1,0)]
    dp=[[0]*n for _ in range(m)]
    def dfs(i,j):
        if dp[i][j]:
            return dp[i][j]
        max_length=1
        for dx,dy in directions:
            x,y=i+dx,j+dy
            if 0<=x<m and 0<=y<n and matrix[x][y]>matrix[i][j]:
                max_length=max(max_length,1+dfs(x,y))
        dp[i][j]=max_length
        return dp[i][j]
    result=0
    for i in range(m):
        for j in range(n):
            result=max(result,dfs(i,j))
    return result

def alienOrder(words):
    from collections import defaultdict,deque
    graph=defaultdict(set)
    in_degree={char:0 for word in words for char in word}
    for i in range(len(words)-1):
        word1,word2=words[i],words[i+1]
        for j in range(min(len(word1),len(word2))):
            if word1[j]!=word2[j]:
                if word2[j] not in graph[word1[j]]:
                    graph[word1[j]].add(word2[j])
                    in_degree[word2[j]]+=1
                break
        else:
            if len(word1)>len(word2):
                return ''
    queue=deque([char for char in in_degree if in_degree[char]==0])
    result=''
    while queue:
        char=queue.popleft()
        result+=char
        for neighbor in graph[char]:
            in_degree[neighbor]-=1
            if in_degree[neighbor]==0:
                queue.append(neighbor)
    return result if len(result)==len(in_degree) else ''

def maxProfit(k,prices):
    if not prices:
        return 0
    n=len(prices)
    if k>=n//2:
        return sum(max(prices[i+1]-prices[i],0) for i in range(n-1))
    dp=[[0]*n for _ in range(k+1)]
    for i in range(1,k+1):
        max_diff=-prices[0]
        for j in range(1,n):
            dp[i][j]=max(dp[i][j-1],prices[j]+max_diff)
            max_diff=max(max_diff,dp[i-1][j]-prices[j])
    return dp[k][n-1]

